FROM jsonb_to_recordset('[{"id": "cap-111-society-043", "exam_id": "cap", "subject_id": "sub-cap-social", "paper_id": "cap-111-society", "question_type": "single_choice", "question_text": "圖(二十三)是某一時期的政治宣傳漫畫，圖中\n「大手」代表當時的國際組織，領導各國對\n抗侵略者。根據內容判斷，該國際組織最可\n能是下列何者？", "options": ["聯合國", "國際聯盟", "華沙公約組織", "石油輸出國家組織 二、題組：(44～54題)                       圖(二十三) 閱讀下列選文，回答第 44 至 45 題： 1855年，美商威廉士洋行的商船航行至臺灣府 安平外海，並派人上岸詢問是否 能在當地貿易。經過安排，船長和臺灣道裕鐸在打狗會面，裕鐸在會談中告知船長， 外國商船如果直接在安平停泊，並不符合規定，臺灣道將受到朝廷處罰，但裕鐸和 打狗地方官員可以私下允許外國商船，停靠遠離政治核心的打狗進行貿易。 然而，實際上官員後來往往放任外國商船停靠安平，未能嚴格執行禁令。過了 數年，新任的臺灣道孔昭慈於1859年，又要求外國商船「不准像之前一樣在安平附 近起卸貨物」。有位英國商人分析：「這並非臺灣道刻意禁止外商在臺灣府貿易，而 是因為府城當地泉州人組成的商人團體，跑去向福建巡撫告狀，指控外國商船收購 物產，造成物價上漲，影響了本地商人的生意。」 & 臺灣道：臺灣建省前，在臺灣的最高文官。"], "correct_answer": 0, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:40+00:00", "source_pdf_sha1": "017dd4352325", "answer_pdf_sha1": "5db25b41f664", "flags": ["needs_image"], "parse_confidence": 0.85, "original_question_number": 43, "raw_text": "43. 圖(二十三)是某一時期的政治宣傳漫畫，圖中\n    「大手」代表當時的國際組織，領導各國對\n    抗侵略者。根據內容判斷，該國際組織最可\n    能是下列何者？\n    (A)聯合國    (B)國際聯盟\n    (C)華沙公約組織 (D)石油輸出國家組織\n\n二、題組：(44～54題)                       圖(二十三)\n閱讀下列選文，回答第 44 至 45 題：\n\n  1855年，美商威廉士洋行的商船航行至臺灣府 安平外海，並派人上岸詢問是否\n能在當地貿易。經過安排，船長和臺灣道裕鐸在打狗會面，裕鐸在會談中告知船長，\n外國商船如果直接在安平停泊，並不符合規定，臺灣道將受到朝廷處罰，但裕鐸和\n打狗地方官員可以私下允許外國商船，停靠遠離政治核心的打狗進行貿易。\n  然而，實際上官員後來往往放任外國商船停靠安平，未能嚴格執行禁令。過了\n數年，新任的臺灣道孔昭慈於1859年，又要求外國商船「不准像之前一樣在安平附\n近起卸貨物」。有位英國商人分析：「這並非臺灣道刻意禁止外商在臺灣府貿易，而\n是因為府城當地泉州人組成的商人團體，跑去向福建巡撫告狀，指控外國商船收購\n物產，造成物價上漲，影響了本地商人的生意。」\n                         & 臺灣道：臺灣建省前，在臺灣的最高文官。"}, "is_active": false, "auto_gradable": false, "difficulty": 3, "explanation": null}, {"id": "cap-111-society-044", "exam_id": "cap", "subject_id": "sub-cap-social", "paper_id": "cap-111-society", "question_type": "single_choice", "question_text": "根據上文中裕鐸與洋行的會談結果，當時臺灣對外貿易的情況，最可能是下列何者？", "options": ["當時臺灣尚未對外開港，裕鐸嚴禁洋商在臺貿易", "當時臺灣尚未對外開港，實際上洋商已來臺貿易", "當時臺灣已經對外開港，洋商可在臺灣各港口貿易", "當時臺灣已經對外開港，裕鐸仍阻撓洋商在臺貿易"], "correct_answer": 1, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:40+00:00", "source_pdf_sha1": "017dd4352325", "answer_pdf_sha1": "5db25b41f664", "flags": [], "parse_confidence": 1.0, "original_question_number": 44, "raw_text": "44. 根據上文中裕鐸與洋行的會談結果，當時臺灣對外貿易的情況，最可能是下列何者？\n    (A)當時臺灣尚未對外開港，裕鐸嚴禁洋商在臺貿易\n    (B)當時臺灣尚未對外開港，實際上洋商已來臺貿易\n    (C)當時臺灣已經對外開港，洋商可在臺灣各港口貿易\n    (D)當時臺灣已經對外開港，裕鐸仍阻撓洋商在臺貿易"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-111-society-045", "exam_id": "cap", "subject_id": "sub-cap-social", "paper_id": "cap-111-society", "question_type": "single_choice", "question_text": "根據上文，外國商人分析臺灣道重申外國商船不得在安平附近起卸貨物的原\n因，最可能與下列何者有關？", "options": ["安平與鹿耳門泥沙淤積，易造成擱淺", "府城商人透過「郊」來維護自身利益", "日本出兵臺灣南部，清帝國提高警戒", "許多府城商人組成「郊」與洋行合作 閱讀下列選文，回答第 46 至 48 題： 臺灣和地形有關的地名，多是古人依照當時的地理環境 所命名，隨著時間變化，原先的山丘、河或湖可能會變遷甚 至消失，僅剩下地名而已。因此，透過地名可推估過去的地 景樣貌，例如「墘」字代表位於某一地物或水體的旁邊，如 厝墘、田墘、港墘與溪墘等，圖(二十四)為「墘」字地名的 分布圖。 小瑜家鄉地名也有「墘」字，雖然現今已經看不到當時 的地貌；為了印證上述命名原則，她找到1921年日治時期家 鄉的地圖(圖二十五)，並將當時的河流及水體標示在現今的 電子地圖(圖二十六)上，發現與上述原則是一致的。              圖(二十四) 圖(二十五)               圖(二十六)"], "correct_answer": 1, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:40+00:00", "source_pdf_sha1": "017dd4352325", "answer_pdf_sha1": "5db25b41f664", "flags": ["needs_image"], "parse_confidence": 0.85, "original_question_number": 45, "raw_text": "45. 根據上文，外國商人分析臺灣道重申外國商船不得在安平附近起卸貨物的原\n    因，最可能與下列何者有關？\n    (A)安平與鹿耳門泥沙淤積，易造成擱淺\n    (B)府城商人透過「郊」來維護自身利益\n    (C)日本出兵臺灣南部，清帝國提高警戒\n    (D)許多府城商人組成「郊」與洋行合作\n\n\n閱讀下列選文，回答第 46 至 48 題：\n\n  臺灣和地形有關的地名，多是古人依照當時的地理環境\n所命名，隨著時間變化，原先的山丘、河或湖可能會變遷甚\n至消失，僅剩下地名而已。因此，透過地名可推估過去的地\n景樣貌，例如「墘」字代表位於某一地物或水體的旁邊，如\n厝墘、田墘、港墘與溪墘等，圖(二十四)為「墘」字地名的\n分布圖。\n  小瑜家鄉地名也有「墘」字，雖然現今已經看不到當時\n的地貌；為了印證上述命名原則，她找到1921年日治時期家\n鄉的地圖(圖二十五)，並將當時的河流及水體標示在現今的\n電子地圖(圖二十六)上，發現與上述原則是一致的。              圖(二十四)\n\n\n\n\n        圖(二十五)               圖(二十六)\n"}, "is_active": false, "auto_gradable": false, "difficulty": 3, "explanation": null}, {"id": "cap-111-society-046", "exam_id": "cap", "subject_id": "sub-cap-social", "paper_id": "cap-111-society", "question_type": "single_choice", "question_text": "根據圖(二十四)中「墘」字地名的分布判斷，下列關於「墘」字地名的推論\n何者最為合理？", "options": ["分布於閩南族群集中區，屬閩南族系的地名", "分布於客家族群集中區，屬客家族系的地名", "分布於現今原住民居住地，為原住民的地名", "受西班牙占領影響，為西班牙語音譯的地名"], "correct_answer": 0, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:40+00:00", "source_pdf_sha1": "017dd4352325", "answer_pdf_sha1": "5db25b41f664", "flags": ["needs_image"], "parse_confidence": 0.85, "original_question_number": 46, "raw_text": "46. 根據圖(二十四)中「墘」字地名的分布判斷，下列關於「墘」字地名的推論\n    何者最為合理？\n    (A)分布於閩南族群集中區，屬閩南族系的地名\n    (B)分布於客家族群集中區，屬客家族系的地名\n    (C)分布於現今原住民居住地，為原住民的地名\n    (D)受西班牙占領影響，為西班牙語音譯的地名\n"}, "is_active": false, "auto_gradable": false, "difficulty": 3, "explanation": null}, {"id": "cap-111-society-047", "exam_id": "cap", "subject_id": "sub-cap-social", "paper_id": "cap-111-society", "question_type": "single_choice", "question_text": "根據圖(二十五)判斷，在日治時期小瑜的家鄉最可能以哪種產業活動為主？", "options": ["水稻耕作", "樟腦提煉", "茶葉種植", "海鹽晒製"], "correct_answer": 0, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:40+00:00", "source_pdf_sha1": "017dd4352325", "answer_pdf_sha1": "5db25b41f664", "flags": ["needs_image"], "parse_confidence": 0.85, "original_question_number": 47, "raw_text": "47. 根據圖(二十五)判斷，在日治時期小瑜的家鄉最可能以哪種產業活動為主？\n    (A)水稻耕作\n    (B)樟腦提煉\n    (C)茶葉種植\n    (D)海鹽晒製\n"}, "is_active": false, "auto_gradable": false, "difficulty": 3, "explanation": null}, {"id": "cap-111-society-048", "exam_id": "cap", "subject_id": "sub-cap-social", "paper_id": "cap-111-society", "question_type": "single_choice", "question_text": "根據上文中地名的命名原則及圖(二十五)與圖(二十六)的資訊判斷，小瑜的家\n鄉地名最可能為下列何者？", "options": ["海墘", "潭墘", "岸壁墘", "黑礁墘 閱讀下列選文，回答第 49 至 51 題： 過去以茶文化為主的亞洲人，對咖啡的接受度越來越高，更逐漸在各地形 成獨特的咖啡文化。近年臺灣也吹起喝咖啡的風潮，路上常看到人手一杯咖 啡。其實早在日治時期，日本就已將飲用咖啡的習慣帶入臺灣，戰後有業者 創立供內用的專業咖啡店，還有廠商生產即溶與罐裝咖啡，但直到九○年代末 期，美式咖啡連鎖品牌進駐臺灣引進外帶現煮咖啡後，咖啡市場才出現了關鍵 性的改變，讓喝咖啡變成日常生活的一部分。2018年時，臺灣平均每人一年喝 下超過200杯咖啡，咖啡豆的進口量是2008年時的兩倍以上，而且咖啡商機還在 持續成長中。 而南韓人比臺灣人更愛喝咖啡，南韓在亞洲地區的咖啡飲用量名列前茅， 根據相關調查報告推估，南韓平均每人一年喝下超過500杯咖啡。咖啡幾乎是 南韓日常生活中不可缺少的一部分，不只是上班族的必備品，也相當受學生喜 愛。在南韓的校園中，不少學生常因熬夜看書導致白天精神不濟，於是飲用咖 啡來提神與增加專注力，但攝取過量咖啡因會有頭暈、心跳加速、睡眠障礙等 症狀，可能不利於青少年神經及心血管系統的發育。南韓政府擔心校園內飲用 咖啡的風氣，對於未來整體的國民健康、醫療資源會產生負面影響，因此修法 規定自2018年9月起，全面禁止在高中以下校園內販售含有咖啡因的飲料。 或許臺灣人的咖啡癮還沒有南韓這麼嚴重，不過我國已有相關法令規範高 中以下校園內飲品及點心的販售項目，違規販售不符規範的商品將被主管機關 要求下架，以避免類似的問題在臺灣發生。"], "correct_answer": 1, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:40+00:00", "source_pdf_sha1": "017dd4352325", "answer_pdf_sha1": "5db25b41f664", "flags": ["needs_image"], "parse_confidence": 0.85, "original_question_number": 48, "raw_text": "48. 根據上文中地名的命名原則及圖(二十五)與圖(二十六)的資訊判斷，小瑜的家\n    鄉地名最可能為下列何者？\n    (A)海墘\n    (B)潭墘\n    (C)岸壁墘\n    (D)黑礁墘\n\n閱讀下列選文，回答第 49 至 51 題：\n\n  過去以茶文化為主的亞洲人，對咖啡的接受度越來越高，更逐漸在各地形\n成獨特的咖啡文化。近年臺灣也吹起喝咖啡的風潮，路上常看到人手一杯咖\n啡。其實早在日治時期，日本就已將飲用咖啡的習慣帶入臺灣，戰後有業者\n創立供內用的專業咖啡店，還有廠商生產即溶與罐裝咖啡，但直到九○年代末\n期，美式咖啡連鎖品牌進駐臺灣引進外帶現煮咖啡後，咖啡市場才出現了關鍵\n性的改變，讓喝咖啡變成日常生活的一部分。2018年時，臺灣平均每人一年喝\n下超過200杯咖啡，咖啡豆的進口量是2008年時的兩倍以上，而且咖啡商機還在\n持續成長中。\n  而南韓人比臺灣人更愛喝咖啡，南韓在亞洲地區的咖啡飲用量名列前茅，\n根據相關調查報告推估，南韓平均每人一年喝下超過500杯咖啡。咖啡幾乎是\n南韓日常生活中不可缺少的一部分，不只是上班族的必備品，也相當受學生喜\n愛。在南韓的校園中，不少學生常因熬夜看書導致白天精神不濟，於是飲用咖\n啡來提神與增加專注力，但攝取過量咖啡因會有頭暈、心跳加速、睡眠障礙等\n症狀，可能不利於青少年神經及心血管系統的發育。南韓政府擔心校園內飲用\n咖啡的風氣，對於未來整體的國民健康、醫療資源會產生負面影響，因此修法\n規定自2018年9月起，全面禁止在高中以下校園內販售含有咖啡因的飲料。\n  或許臺灣人的咖啡癮還沒有南韓這麼嚴重，不過我國已有相關法令規範高\n中以下校園內飲品及點心的販售項目，違規販售不符規範的商品將被主管機關\n要求下架，以避免類似的問題在臺灣發生。\n"}, "is_active": false, "auto_gradable": false, "difficulty": 3, "explanation": null}, {"id": "cap-111-society-049", "exam_id": "cap", "subject_id": "sub-cap-social", "paper_id": "cap-111-society", "question_type": "single_choice", "question_text": "文中針對我國咖啡的相關敘述，下列何者最適當？", "options": ["咖啡產品貿易總額超越茶產品", "咖啡豆的進出口貿易呈現出超", "飲用咖啡的習慣受到文化交流影響", "國小內販售咖啡將會遭受刑罰處罰"], "correct_answer": 2, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:40+00:00", "source_pdf_sha1": "017dd4352325", "answer_pdf_sha1": "5db25b41f664", "flags": [], "parse_confidence": 1.0, "original_question_number": 49, "raw_text": "49. 文中針對我國咖啡的相關敘述，下列何者最適當？\n    (A)咖啡產品貿易總額超越茶產品\n    (B)咖啡豆的進出口貿易呈現出超\n    (C)飲用咖啡的習慣受到文化交流影響\n    (D)國小內販售咖啡將會遭受刑罰處罰\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-111-society-050", "exam_id": "cap", "subject_id": "sub-cap-social", "paper_id": "cap-111-society", "question_type": "single_choice", "question_text": "根據文中內容判斷，南韓政府的作法與下列何項敘述最相符？", "options": ["透過負向誘因影響校內師生的消費能力", "透過正向誘因影響校內商品的販售種類", "透過制度變革影響校內師生的消費能力", "透過制度變革影響校內商品的販售種類"], "correct_answer": 3, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:40+00:00", "source_pdf_sha1": "017dd4352325", "answer_pdf_sha1": "5db25b41f664", "flags": [], "parse_confidence": 1.0, "original_question_number": 50, "raw_text": "50. 根據文中內容判斷，南韓政府的作法與下列何項敘述最相符？\n    (A)透過負向誘因影響校內師生的消費能力\n    (B)透過正向誘因影響校內商品的販售種類\n    (C)透過制度變革影響校內師生的消費能力\n    (D)透過制度變革影響校內商品的販售種類\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-111-society-051", "exam_id": "cap", "subject_id": "sub-cap-social", "paper_id": "cap-111-society", "question_type": "single_choice", "question_text": "文中所提及南韓政府修改法律的目的，與下列我國的何項作法最類似？", "options": ["受監護宣告者自行訂定的契約不具效力", "雇主不得因性別因素而對員工有差別待遇", "國小學童不得出入有害身心發展的不良場所", "家庭暴力受害者可聲請保護令以避免受到傷害 閱讀下列選文，回答第 52 至 54 題： 空氣汙染是當代世界嚴重的問題，過去的 英國也曾深受空汙的危害。日本 明治時代文學 家夏目漱石在旅英期間的日記中寫道：「在倫敦 的街上散步時吐了口痰，當我看到自己吐出一團 全黑的物體時真是吃驚。幾百萬市民每天都吸著 煤煙和塵埃，汙染著他們的肺。」當時人們以煤 作為驅動蒸汽機以及家中暖爐、廚具的燃料，      圖(二十七) 加上西歐地區盛行風的吹拂，使空氣汙染物不斷飄向城市的下風處，形成如 圖(二十七)煙霧瀰漫的景觀。 燃煤帶來的空氣汙染會影響健康，可能降低新生兒存活率，或是使得兒童 發育遲緩。十九世紀時英國部分城市的居民居住區域分布也反映出貧富差距， 資本家與中產階級為了尋求較好的生活品質，紛紛遷往城市中汙染較少的區 域，而較為窮困的低技術勞動階級，因受工作地點和經濟考量所限，只能居住 於汙染嚴重的區域。因此，思想家恩格斯在當時就發出「只有勞動階級才會呼 吸受汙染的空氣」的不平之鳴。"], "correct_answer": 2, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:40+00:00", "source_pdf_sha1": "017dd4352325", "answer_pdf_sha1": "5db25b41f664", "flags": ["needs_image"], "parse_confidence": 0.85, "original_question_number": 51, "raw_text": "51. 文中所提及南韓政府修改法律的目的，與下列我國的何項作法最類似？\n    (A)受監護宣告者自行訂定的契約不具效力\n    (B)雇主不得因性別因素而對員工有差別待遇\n    (C)國小學童不得出入有害身心發展的不良場所\n    (D)家庭暴力受害者可聲請保護令以避免受到傷害\n\n\n\n閱讀下列選文，回答第 52 至 54 題：\n\n   空氣汙染是當代世界嚴重的問題，過去的\n英國也曾深受空汙的危害。日本 明治時代文學\n家夏目漱石在旅英期間的日記中寫道：「在倫敦\n的街上散步時吐了口痰，當我看到自己吐出一團\n全黑的物體時真是吃驚。幾百萬市民每天都吸著\n煤煙和塵埃，汙染著他們的肺。」當時人們以煤\n作為驅動蒸汽機以及家中暖爐、廚具的燃料，      圖(二十七)\n加上西歐地區盛行風的吹拂，使空氣汙染物不斷飄向城市的下風處，形成如\n圖(二十七)煙霧瀰漫的景觀。\n   燃煤帶來的空氣汙染會影響健康，可能降低新生兒存活率，或是使得兒童\n發育遲緩。十九世紀時英國部分城市的居民居住區域分布也反映出貧富差距，\n資本家與中產階級為了尋求較好的生活品質，紛紛遷往城市中汙染較少的區\n域，而較為窮困的低技術勞動階級，因受工作地點和經濟考量所限，只能居住\n於汙染嚴重的區域。因此，思想家恩格斯在當時就發出「只有勞動階級才會呼\n吸受汙染的空氣」的不平之鳴。\n"}, "is_active": false, "auto_gradable": false, "difficulty": 3, "explanation": null}, {"id": "cap-111-society-052", "exam_id": "cap", "subject_id": "sub-cap-social", "paper_id": "cap-111-society", "question_type": "single_choice", "question_text": "文中日本文學家描述的城市現象，與下列何者的關係最密切？", "options": ["工業革命", "宗教改革", "啟蒙運動", "文藝復興"], "correct_answer": 0, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:40+00:00", "source_pdf_sha1": "017dd4352325", "answer_pdf_sha1": "5db25b41f664", "flags": [], "parse_confidence": 1.0, "original_question_number": 52, "raw_text": "52. 文中日本文學家描述的城市現象，與下列何者的關係最密切？\n    (A)工業革命\n    (B)宗教改革\n    (C)啟蒙運動\n    (D)文藝復興\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-111-society-053", "exam_id": "cap", "subject_id": "sub-cap-social", "paper_id": "cap-111-society", "question_type": "single_choice", "question_text": "圖(二十八)是文中國家某空氣汙染嚴重的城市示意\n圖。已知圖中某處為低技術勞動階級居住的區域，\n根據上文及考量盛行風向的影響，此處最可能位於\n圖中甲、乙、丙、丁何處？", "options": ["甲", "乙", "丙", "丁 圖(二十八)"], "correct_answer": 1, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:40+00:00", "source_pdf_sha1": "017dd4352325", "answer_pdf_sha1": "5db25b41f664", "flags": ["needs_image"], "parse_confidence": 0.85, "original_question_number": 53, "raw_text": "53. 圖(二十八)是文中國家某空氣汙染嚴重的城市示意\n    圖。已知圖中某處為低技術勞動階級居住的區域，\n    根據上文及考量盛行風向的影響，此處最可能位於\n    圖中甲、乙、丙、丁何處？\n    (A)甲\n    (B)乙\n    (C)丙\n    (D)丁\n                              圖(二十八)"}, "is_active": false, "auto_gradable": false, "difficulty": 3, "explanation": null}, {"id": "cap-111-society-054", "exam_id": "cap", "subject_id": "sub-cap-social", "paper_id": "cap-111-society", "question_type": "single_choice", "question_text": "文中關於城市居民居住區域分布所呈現的問題，是下列何者的關懷重點？", "options": ["社會主義", "民族主義", "帝國主義", "法西斯主義"], "correct_answer": 0, "correct_answer